import{_ as o,c as r,o as i,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const b=JSON.parse('{"title":"v1.2.4: New Database Check Command, Desktop Bug Fixes","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.2.4.md","filePath":"en/changelog/v1.2.4.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.2.4.md"};function s(d,a,h,l,c,u){return i(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-2-4-new-database-check-command-desktop-bug-fixes" tabindex="-1">v1.2.4: New Database Check Command, Desktop Bug Fixes <a class="header-anchor" href="#v1-2-4-new-database-check-command-desktop-bug-fixes" aria-label="Permalink to “v1.2.4: New Database Check Command, Desktop Bug Fixes”">​</a></h1><p><strong>Release Date</strong>: February 15, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update <strong>adds a database check command</strong> for easier troubleshooting, and fixes some desktop bugs.</p><hr><h2 id="new-feature-database-check-command" tabindex="-1">New Feature: Database Check Command <a class="header-anchor" href="#new-feature-database-check-command" aria-label="Permalink to “New Feature: Database Check Command”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added the <code>opencode db</code> command, allowing direct querying and inspection of OpenCode&#39;s SQLite database.</p><h3 id="what-is-opencode-db" tabindex="-1">What is opencode db? <a class="header-anchor" href="#what-is-opencode-db" aria-label="Permalink to “What is opencode db?”">​</a></h3><p>This is a <strong>developer tool</strong> that lets you directly view content stored in the database, such as OpenCode session data and file records.</p><h3 id="when-to-use-it" tabindex="-1">When to use it? <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to “When to use it?”">​</a></h3><p>You can use it to troubleshoot the following issues:</p><table tabindex="0"><thead><tr><th>Issue</th><th>Usage</th></tr></thead><tbody><tr><td>Can&#39;t find session</td><td><code>opencode db &quot;SELECT * FROM sessions&quot;</code></td></tr><tr><td>Abnormal file records</td><td><code>opencode db &quot;SELECT * FROM files&quot;</code></td></tr><tr><td>Want to see database structure</td><td><code>opencode db &quot;.schema&quot;</code></td></tr></tbody></table><p><strong>Note</strong>: Regular users generally don&#39;t need this command; only use it when encountering data issues.</p><hr><h2 id="new-feature-json-migration-improvement" tabindex="-1">New Feature: JSON Migration Improvement <a class="header-anchor" href="#new-feature-json-migration-improvement" aria-label="Permalink to “New Feature: JSON Migration Improvement”">​</a></h2><h3 id="what-was-updated-1" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-1" aria-label="Permalink to “What was updated?”">​</a></h3><p>When migrating from JSON format to SQLite database, all IDs are now derived from file paths to ensure consistency.</p><h3 id="what-are-the-benefits" tabindex="-1">What are the benefits? <a class="header-anchor" href="#what-are-the-benefits" aria-label="Permalink to “What are the benefits?”">​</a></h3><p>Ensures IDs remain consistent after data migration, avoiding data association errors.</p><hr><h2 id="bug-fix-desktop-file-tree-crash" tabindex="-1">Bug Fix: Desktop File Tree Crash <a class="header-anchor" href="#bug-fix-desktop-file-tree-crash" aria-label="Permalink to “Bug Fix: Desktop File Tree Crash”">​</a></h2><h3 id="the-previous-problem" tabindex="-1">The Previous Problem <a class="header-anchor" href="#the-previous-problem" aria-label="Permalink to “The Previous Problem”">​</a></h3><p>In the desktop application, opening the file tree in certain situations could cause the program to crash.</p><h3 id="the-current-situation" tabindex="-1">The Current Situation <a class="header-anchor" href="#the-current-situation" aria-label="Permalink to “The Current Situation”">​</a></h3><p>This stack overflow issue has been fixed, and the file tree can now be used normally.</p><hr><h2 id="bug-fix-notification-clearing" tabindex="-1">Bug Fix: Notification Clearing <a class="header-anchor" href="#bug-fix-notification-clearing" aria-label="Permalink to “Bug Fix: Notification Clearing”">​</a></h2><h3 id="the-previous-problem-1" tabindex="-1">The Previous Problem <a class="header-anchor" href="#the-previous-problem-1" aria-label="Permalink to “The Previous Problem”">​</a></h3><p>Desktop application notifications kept piling up and couldn&#39;t be cleared.</p><h3 id="the-current-situation-1" tabindex="-1">The Current Situation <a class="header-anchor" href="#the-current-situation-1" aria-label="Permalink to “The Current Situation”">​</a></h3><p>Added a &quot;Clear Notifications&quot; action, allowing manual clearing of the notification list.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Encountered file tree crash on desktop</td><td>✅ Upgrade</td></tr><tr><td>Want to troubleshoot database issues</td><td>✅ Upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next release</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',37),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-optional" tabindex="-1">Technical Details (Optional) <a class="header-anchor" href="#technical-details-optional" aria-label="Permalink to “Technical Details (Optional)”">​</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Added db command for database inspection and querying</li><li>Derive all IDs from file paths during JSON migration</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Clear notifications action</li><li>Fixed stack overflow issue in file tree component</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const m=o(n,[["render",s]]);export{b as __pageData,m as default};
